export interface Hero {
  name: string;
  title: string;
  village: string;
  rank: string;
  clan: string;
  image: string;
  bio: string;
  abilities: string[];
  achievements: string[];
  signature: string;
  relationships: string[];
  quote: string;
  arc: "Part 1" | "Shippuden" | "War Arc";
  powerStats: {
    speed: number;
    iq: number;
    chakra: number;
    taijutsu: number;
  };
}

export interface War {
  name: string;
  duration: string;
  description: string;
  keyEvents: string[];
  casualties: string;
  outcome: string;
  image: string | string[];
  timeline: string[];
}

export interface Mission {
  name: string;
  rank: "D" | "C" | "B" | "A" | "S";
  team: string;
  objective: string;
  outcome: string;
  notableEvents: string[];
  quote: string;
}

export interface VideoEntry {
  title: string;
  description: string;
  videoId: string;
  category: string;
}

export interface Clan {
  name: string;
  kekkeiGenkai: string;
  specialty: string;
  members: string[];
}

export interface Jutsu {
  name: string;
  type: string;
  rank: "C" | "B" | "A" | "S";
  users: string[];
  firstAppearance: string;
}

export interface CompleteCharacter {
  name: string;
  title: string;
  village: string;
  aura: "Legendary" | "Elite" | "Notable";
  description: string;
  kekkeiGenkai?: string;
  abilities?: string[];
  status?: string;
}

